def main(alert):
    attachments = alert.get('attachments', [])
    if not attachments:
        return {'has_attachments': False, 'attachments': [], 'count': 0}
    parsed = []
    for att in attachments:
        parsed.append({
            'filename': att.get('filename', 'unknown'),
            'sha256': att.get('sha256', ''),
            'md5': att.get('md5', ''),
            'size': att.get('size', 0),
            'mime_type': att.get('content_type', att.get('mime_type', 'application/octet-stream')),
            'file_id': att.get('file_id', att.get('id', ''))
        })
    return {'has_attachments': True, 'attachments': parsed, 'count': len(parsed)}

